GRID_SHAPE: tuple[int, int] = (2048, 8)
GRID_MAP: tuple[int, int, int] = (-1, 0, 1)
GRID_HEX: bytes = b''
DELTA: np.float32 = np.float32(0.125)


def dequantize_numpy(blocks: np.ndarray, grid: np.ndarray) -> np.ndarray:
    n_blocks = blocks.shape[0]

    d, rest = np.hsplit(blocks, [2])
    qs, qh = np.hsplit(rest, [QK_K // 8])

    d = d.view(np.float16).astype(np.float32)
    qh = qh.view(np.uint16)

    dl = d * (2 * ((qh >> 12) & 7) + 1)
    dl = dl.reshape((n_blocks, -1, 1, 1))
    delta = np.where((qh & np.uint16(0x8000)) == 0, DELTA, -DELTA)
    delta = delta.reshape((n_blocks, -1, 1, 1))

    qh = qh.reshape((n_blocks, -1, 1)) >> np.array([0, 3, 6, 9], dtype=np.uint16).reshape((1, 1, 4))
    qs = qs.astype(np.uint16) | ((qh & 7) << 8).reshape((n_blocks, -1))

    grid = np.take_along_axis(grid, qs.reshape((n_blocks, -1, 1, 1)), axis=-2)
    grid = grid.reshape((n_blocks, -1, 4, 8))

    return (dl * (grid + delta)).reshape((n_blocks, QK_K))
